+fn is_quit_frame(frame: &RespFrame) -> bool {
+    if let RespFrame::Array(Some(items)) = frame
+        && let Some(RespFrame::BulkString(Some(cmd))) = items.first()
+    {
+        return cmd.eq_ignore_ascii_case(b"QUIT");
